defaultMarkers:
{{(() => {
    const markers = [];

    // Pickup marker (green)
    const pickupLat = PickupLatHidden.text || GetOrderDetails.data[0]?.pickup_lat;
    const pickupLng = PickupLngHidden.text || GetOrderDetails.data[0]?.pickup_lng;
    if (pickupLat && pickupLng) {
      markers.push({
        lat: parseFloat(pickupLat),
        long: parseFloat(pickupLng),
        title: "📍 Pickup: " + (PickupAddressInput.text || GetOrderDetails.data[0]?.pickup_name),
        color: "green"
      });
    }

    // Dropoff marker (red)
    const dropoffLat = DropoffLatHidden.text || GetOrderDetails.data[0]?.dropoff_lat;
    const dropoffLng = DropoffLngHidden.text || GetOrderDetails.data[0]?.dropoff_lng;
    if (dropoffLat && dropoffLng) {
      markers.push({
        lat: parseFloat(dropoffLat),
        long: parseFloat(dropoffLng),
        title: "🚚 Delivery: " + (DropoffAddressInput.text || GetOrderDetails.data[0]?.dropoff_name),
        color: "red"
      });
    }

    return markers;
  })()}}
